"use client";

import * as React from "react";
import {
  IconCrown,
  IconTicket,
  IconGift,
  IconCoin,
  IconShare,
  IconArrowRight,
  IconCar,
  IconBuildingAirport,
  IconBolt,
} from "@tabler/icons-react";

import {
  PageHeader,
  BottomActionBar,
  LoyaltySummaryCard,
  RadioCard,
  RadioCardGroup,
  ListCard,
  TicketStub,
  FilterChips,
  Badge,
  Button,
  Input,
  Separator,
  StatGroup,
  ExpiryBadge,
  CopyButton,
  Icon,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  formatCurrency,
} from "@gunjo/ui";

import {
  MEMBER,
  PLANS,
  COUPONS,
  REFERRAL,
  CURRENT_PLAN_ID,
  type Coupon,
  type CouponFilter,
} from "./data";

const RANK_BADGE: Record<string, React.ReactNode> = {
  ゴールド: (
    <Badge variant="warning" icon={<IconCrown className="size-3.5" aria-hidden="true" />}>
      ゴールド会員
    </Badge>
  ),
};

const COUPON_FILTERS = [
  { value: "all", label: "すべて" },
  { value: "available", label: "利用可能" },
  { value: "expiring", label: "期限間近" },
  { value: "used", label: "使用済" },
] as const;

const COUPON_STATUS_BADGE: Record<Coupon["state"], React.ReactNode> = {
  available: <Badge variant="success">利用可能</Badge>,
  expiring: <Badge variant="warning">期限間近</Badge>,
  used: <Badge variant="outline">使用済</Badge>,
};

function couponIcon(target: string) {
  if (target.includes("空港")) return <IconBuildingAirport className="size-5 text-warning" aria-hidden="true" />;
  return <IconTicket className="size-5 text-primary" aria-hidden="true" />;
}

export default function TaxiMembershipPage() {
  // "Today" pinned for SSR-deterministic ExpiryBadge classification.
  const today = "2026-06-28";

  const [selectedPlan, setSelectedPlan] = React.useState<string>(CURRENT_PLAN_ID);
  const [couponFilter, setCouponFilter] = React.useState<CouponFilter>("all");
  const [redeemCode, setRedeemCode] = React.useState("");
  const [activeCoupon, setActiveCoupon] = React.useState<Coupon | null>(null);

  const visibleCoupons = React.useMemo(
    () => (couponFilter === "all" ? COUPONS : COUPONS.filter((c) => c.state === couponFilter)),
    [couponFilter]
  );

  const filterCounts = React.useMemo(
    () => ({
      all: COUPONS.length,
      available: COUPONS.filter((c) => c.state === "available").length,
      expiring: COUPONS.filter((c) => c.state === "expiring").length,
      used: COUPONS.filter((c) => c.state === "used").length,
    }),
    []
  );

  const planChanged = selectedPlan !== CURRENT_PLAN_ID;
  const selectedPlanObj = PLANS.find((p) => p.id === selectedPlan);

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background">
      <PageHeader
        title="会員・クーポン"
        subtitle="都タクシー アプリ会員"
        onBack={() => {}}
        actions={
          <Button variant="ghost" size="icon" aria-label="ポイント履歴">
            <Icon icon={IconCoin} size="md" decorative />
          </Button>
        }
      />

      {/* pb leaves room for the sticky BottomActionBar */}
      <main className="flex-1 space-y-7 px-4 pb-40 pt-4">
        {/* ───────── 会員ステータス hero ───────── */}
        <section aria-labelledby="status-h">
          <h2 id="status-h" className="sr-only">
            会員ステータス
          </h2>
          <LoyaltySummaryCard
            tone="brand"
            meta={
              <span>
                {MEMBER.name} 様
                <span className="ml-2 opacity-70">会員番号 {MEMBER.number}</span>
              </span>
            }
            tier={RANK_BADGE[MEMBER.rank]}
            balanceLabel="保有ポイント"
            balance={MEMBER.points.toLocaleString("ja-JP")}
            unit="P"
            secondary={[
              { label: "今月の獲得", value: `+${MEMBER.earnedThisMonth.toLocaleString("ja-JP")} P` },
              { label: "会員ランク有効期限", value: "2027/03/31" },
            ]}
            progress={{
              value: MEMBER.rankValue,
              max: MEMBER.rankMax,
              label: MEMBER.rankRemainingLabel,
              caption: MEMBER.rankCaption,
            }}
            alert={
              <span>
                {MEMBER.expiringPoints} P が 2026/07/31 に失効予定
              </span>
            }
            action={
              <Button variant="secondary" size="sm" className="w-full">
                ポイント履歴をみる
                <IconArrowRight className="ml-1 size-4" aria-hidden="true" />
              </Button>
            }
          />
        </section>

        {/* ───────── ポイント strip ───────── */}
        <section aria-labelledby="points-h" className="space-y-3">
          <h2 id="points-h" className="text-base font-bold text-foreground">
            ポイント
          </h2>
          <StatGroup
            cols={3}
            items={[
              { label: "保有ポイント", value: `${MEMBER.points.toLocaleString("ja-JP")} P` },
              { label: "今月の獲得", value: `+${MEMBER.earnedThisMonth} P`, trend: "up" },
              { label: "失効予定", value: `${MEMBER.expiringPoints} P`, hint: "07/31まで" },
            ]}
          />
        </section>

        <Separator />

        {/* ───────── サブスク / 定額乗り放題 ───────── */}
        <section aria-labelledby="plan-h" className="space-y-3">
          <div className="flex items-center justify-between">
            <h2 id="plan-h" className="text-base font-bold text-foreground">
              定額乗り放題プラン
            </h2>
            <Badge variant="info">加入中: スタンダード</Badge>
          </div>
          <p className="text-sm text-muted-foreground">
            毎月定額でおトクに。プランはいつでも変更・解約できます。
          </p>
          <RadioCardGroup
            value={selectedPlan}
            onValueChange={setSelectedPlan}
            aria-label="定額乗り放題プランを選択"
            className="space-y-3"
          >
            {PLANS.map((plan) => (
              <RadioCard
                key={plan.id}
                value={plan.id}
                title={
                  <span className="flex items-center gap-2">
                    {plan.name}
                    {plan.id === CURRENT_PLAN_ID && (
                      <Badge variant="secondary" className="font-normal">
                        現在のプラン
                      </Badge>
                    )}
                  </span>
                }
                description={plan.description}
                tags={plan.tags.map((t) => (
                  <Badge key={t} variant="outline">
                    {t}
                  </Badge>
                ))}
                price={
                  <span>
                    月額 {formatCurrency(plan.monthly)}
                  </span>
                }
                highlight={
                  <span className="flex items-center gap-1 text-success">
                    <IconBolt className="size-3.5" aria-hidden="true" />
                    {plan.highlight}
                  </span>
                }
                leading={<IconCar className="size-5 text-muted-foreground" aria-hidden="true" />}
              />
            ))}
          </RadioCardGroup>
        </section>

        <Separator />

        {/* ───────── クーポン ───────── */}
        <section aria-labelledby="coupon-h" className="space-y-3">
          <h2 id="coupon-h" className="text-base font-bold text-foreground">
            クーポン
          </h2>

          {/* redeem a code */}
          <form
            className="flex items-end gap-2"
            onSubmit={(e) => {
              e.preventDefault();
              setRedeemCode("");
            }}
          >
            <div className="flex-1">
              <Input
                label="クーポンコード / 紹介コード"
                placeholder="例: MTCFIRST500"
                value={redeemCode}
                onChange={(e) => setRedeemCode(e.target.value)}
                autoCapitalize="characters"
                autoCorrect="off"
                spellCheck={false}
              />
            </div>
            <Button type="submit" disabled={redeemCode.trim().length === 0} className="shrink-0">
              追加
            </Button>
          </form>

          <FilterChips
            aria-label="クーポンの絞り込み"
            items={COUPON_FILTERS.map((f) => ({
              value: f.value,
              label: f.label,
              count: filterCounts[f.value],
            }))}
            value={couponFilter}
            onValueChange={(v) => setCouponFilter(v as CouponFilter)}
          />

          <ul className="space-y-2.5">
            {visibleCoupons.map((coupon) => (
              <li key={coupon.id}>
                <ListCard
                  severity={coupon.state === "expiring" ? "warning" : "neutral"}
                  selected={false}
                  leading={couponIcon(coupon.target)}
                  title={
                    <span className="flex items-baseline gap-2">
                      <span className="text-base font-bold text-foreground">{coupon.value}</span>
                      <span className="text-sm text-muted-foreground">{coupon.title}</span>
                    </span>
                  }
                  description={
                    <span className="block">
                      {coupon.target}・{coupon.condition}
                    </span>
                  }
                  tags={
                    <ExpiryBadge value={coupon.expiresAt} today={today} warnWithinDays={14} />
                  }
                  status={COUPON_STATUS_BADGE[coupon.state]}
                  onSelect={
                    coupon.state === "used" ? undefined : () => setActiveCoupon(coupon)
                  }
                />
              </li>
            ))}
          </ul>
          {visibleCoupons.length === 0 && (
            <p className="py-6 text-center text-sm text-muted-foreground">
              該当するクーポンはありません。
            </p>
          )}
        </section>

        <Separator />

        {/* ───────── 友達紹介 ───────── */}
        <section aria-labelledby="referral-h" className="space-y-3">
          <h2 id="referral-h" className="text-base font-bold text-foreground">
            友達紹介
          </h2>
          <div className="rounded-xl border bg-card p-4 text-card-foreground">
            <div className="flex items-start gap-3">
              <span className="mt-0.5 flex size-9 shrink-0 items-center justify-center rounded-full bg-primary/10">
                <IconGift className="size-5 text-primary" aria-hidden="true" />
              </span>
              <div className="min-w-0 flex-1">
                <p className="text-sm font-medium text-foreground">紹介特典</p>
                <p className="text-sm text-muted-foreground">{REFERRAL.reward}</p>
              </div>
            </div>

            <div className="mt-4">
              <span id="referral-code-label" className="text-xs font-medium text-muted-foreground">
                あなたの紹介コード
              </span>
              <div
                className="mt-1 flex items-center justify-between gap-2 rounded-lg border border-dashed bg-muted/40 px-3 py-2"
                aria-labelledby="referral-code-label"
              >
                <code className="font-mono text-lg font-bold tracking-wider text-foreground">
                  {REFERRAL.code}
                </code>
                <CopyButton
                  value={REFERRAL.code}
                  variant="label"
                  copyLabel="紹介コードをコピー"
                  copiedLabel="コピーしました"
                />
              </div>
            </div>

            <Button variant="outline" className="mt-3 w-full">
              <IconShare className="mr-1.5 size-4" aria-hidden="true" />
              紹介リンクを共有する
            </Button>
          </div>
        </section>
      </main>

      {/* ───────── sticky bottom action ───────── */}
      <BottomActionBar
        maxWidth="md"
        actions={
          <Button size="lg" disabled={!planChanged}>
            {planChanged ? "プランを変更する" : "加入中のプラン"}
          </Button>
        }
      >
        <div className="min-w-0">
          <p className="truncate text-xs text-muted-foreground">
            {planChanged ? "選択中のプラン" : "現在のプラン"}
          </p>
          <p className="truncate text-sm font-bold text-foreground">
            {selectedPlanObj?.name}
            <span className="ml-1 font-normal text-muted-foreground">
              月額 {formatCurrency(selectedPlanObj?.monthly ?? 0)}
            </span>
          </p>
        </div>
      </BottomActionBar>

      {/* ───────── coupon present-to-use sheet ───────── */}
      <Sheet open={activeCoupon != null} onOpenChange={(o) => !o && setActiveCoupon(null)}>
        <SheetContent side="bottom" closeLabel="閉じる" className="rounded-t-2xl">
          {activeCoupon && (
            <>
              <SheetHeader>
                <SheetTitle>{activeCoupon.title}</SheetTitle>
                <SheetDescription>
                  乗務員にこの画面を提示するか、コードを入力してください。
                </SheetDescription>
              </SheetHeader>
              <div className="mt-4">
                <TicketStub
                  value={activeCoupon.code}
                  format="qr"
                  codeLabel={activeCoupon.code}
                  codeAlt={`クーポンコード ${activeCoupon.code} のQRコード`}
                >
                  <div className="space-y-1">
                    <p className="text-2xl font-bold text-foreground">{activeCoupon.value}</p>
                    <p className="text-sm text-muted-foreground">{activeCoupon.target}</p>
                    <p className="text-sm text-muted-foreground">{activeCoupon.condition}</p>
                    <p className="pt-1 text-xs text-muted-foreground">
                      利用期限 {activeCoupon.expiresAt.replaceAll("-", "/")}
                    </p>
                  </div>
                </TicketStub>
              </div>
              <Button className="mt-4 w-full" size="lg" onClick={() => setActiveCoupon(null)}>
                このクーポンを使う
              </Button>
            </>
          )}
        </SheetContent>
      </Sheet>
    </div>
  );
}

// Realistic mock content for the 都タクシー (Miyako Taxi) 会員・サブスク・クーポン screen.
// Plain data only — no JSX, no functions — so it can be imported from either
// a Server or Client component without an SSR boundary problem.

export type CouponState = "available" | "expiring" | "used";

export interface Coupon {
  id: string;
  title: string;
  /** e.g. "300円OFF" / "10%OFF" — the dominant value line. */
  value: string;
  /** What the coupon applies to. */
  target: string;
  /** Minimum spend / conditions. */
  condition: string;
  /** ISO date used by ExpiryBadge + display. */
  expiresAt: string;
  state: CouponState;
  /** The redeemable code shown on the present-to-use stub. */
  code: string;
}

export interface Plan {
  id: string;
  name: string;
  /** Monthly price in yen. */
  monthly: number;
  /** Short positioning line. */
  description: string;
  /** Value hook ("月4回でモト"). */
  highlight: string;
  /** Chip labels above the title. */
  tags: string[];
}

export const MEMBER = {
  name: "佐藤 美咲",
  number: "MTC-0420-7781",
  rank: "ゴールド",
  points: 3480,
  earnedThisMonth: 620,
  expiringPoints: 180,
  expiringPointsAt: "2026-07-31",
  // progress to プラチナ
  rankValue: 21500,
  rankMax: 30000,
  rankRemainingLabel: "プラチナまであと ¥8,500",
  rankCaption: "年間ご利用額 ¥21,500 / ¥30,000",
  rankExpiresAt: "2027-03-31",
};

export const CURRENT_PLAN_ID = "standard";

export const PLANS: Plan[] = [
  {
    id: "light",
    name: "ライト",
    monthly: 980,
    description: "初乗り料金が毎月2回まで無料。たまに乗る方に。",
    highlight: "月2回でモト",
    tags: ["お試し"],
  },
  {
    id: "standard",
    name: "スタンダード",
    monthly: 2480,
    description: "市内乗り放題（1回2,000円まで）。通勤・通院に。",
    highlight: "月4回でモト",
    tags: ["人気No.1"],
  },
  {
    id: "premium",
    name: "プレミアム",
    monthly: 4980,
    description: "市内乗り放題＋空港定額20%OFF＋優先配車。",
    highlight: "月8回でモト",
    tags: ["お得", "優先配車"],
  },
];

export const COUPONS: Coupon[] = [
  {
    id: "cp-first",
    title: "初回乗車クーポン",
    value: "500円OFF",
    target: "全車種・全エリア",
    condition: "1,000円以上のご乗車",
    expiresAt: "2026-08-31",
    state: "available",
    code: "MTCFIRST500",
  },
  {
    id: "cp-airport",
    title: "空港定額 10%OFF",
    value: "10%OFF",
    target: "空港定額便",
    condition: "伊丹・関空ゆき",
    expiresAt: "2026-07-05",
    state: "expiring",
    code: "MTCAIR10",
  },
  {
    id: "cp-friend",
    title: "友達紹介クーポン",
    value: "300円OFF",
    target: "全車種・全エリア",
    condition: "紹介コードご利用特典",
    expiresAt: "2026-09-30",
    state: "available",
    code: "MTCREF300",
  },
  {
    id: "cp-rain",
    title: "雨の日クーポン",
    value: "200円OFF",
    target: "市内一般乗車",
    condition: "次回ご乗車時",
    expiresAt: "2026-06-20",
    state: "used",
    code: "MTCRAIN200",
  },
];

export const REFERRAL = {
  code: "MISAKI-7781",
  /** What both sides get. */
  reward: "紹介した方・された方に 各300ポイント",
  shareUrl: "https://miyako-taxi.example.jp/r/MISAKI-7781",
};

export type CouponFilter = "all" | "available" | "expiring" | "used";
